import java.util.Scanner;
import java.util.Arrays;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Limiting the input size to prevent buffer overflow
        int maxLength = 10;
        byte[] buffer = new byte[maxLength];
        byte[] inputBytes = name.getBytes();

        if (inputBytes.length > maxLength) {
            System.arraycopy(inputBytes, 0, buffer, 0, maxLength);
        } else {
            System.arraycopy(inputBytes, 0, buffer, 0, inputBytes.length);
            Arrays.fill(buffer, inputBytes.length, maxLength, (byte) 0); // Fill remaining bytes with zeros
        }

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
